아래는 논블로킹 소켓에서 들어오는 연결을 처리하기 위해 `epoll_wait()`을 사용하는 간단한 C 예제입니다. 이 예제에서는 `epoll_pwait2()`를 사용하여 `min_events`와 `maxevents`를 설정합니다. 이 코드는 기본적인 이벤트 루프를 설정하고, 들어오는 연결을 처리하는 방법을 보여줍니다.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/epoll.h>
#include <netinet/in.h>
#include <errno.h>

#define PORT 8080
#define MAX_EVENTS 64
#define MIN_EVENTS 8

int set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    if (flags == -1) return -1;
    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int main() {
    int listen_fd, epoll_fd;
    struct sockaddr_in addr;
    struct epoll_event event, events[MAX_EVENTS];

    // Create listening socket
    listen_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (listen_fd == -1) {
        perror("socket");
        exit(EXIT_FAILURE);
    }

    // Set socket to non-blocking
    if (set_nonblocking(listen_fd) == -1) {
        perror("set_nonblocking");
        close(listen_fd);
        exit(EXIT_FAILURE);
    }

    // Bind socket
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons(PORT);

    if (bind(listen_fd, (struct sockaddr *)&addr, sizeof(addr)) == -1) {
        perror("bind");
        close(listen_fd);
        exit(EXIT_FAILURE);
    }

    // Listen on socket
    if (listen(listen_fd, SOMAXCONN) == -1) {
        perror("listen");
        close(listen_fd);
        exit(EXIT_FAILURE);
    }

    // Create epoll instance
    epoll_fd = epoll_create1(0);
    if (epoll_fd == -1) {
        perror("epoll_create1");
        close(listen_fd);
        exit(EXIT_FAILURE);
    }

    // Add listening socket to epoll
    event.events = EPOLLIN;
    event.data.fd = listen_fd;
    if (epoll_ctl(epoll_fd, EPOLL_CTL_ADD, listen_fd, &event) == -1) {
        perror("epoll_ctl");
        close(listen_fd);
        close(epoll_fd);
        exit(EXIT_FAILURE);
    }

    // Event loop
    while (1) {
        int n, i;
        struct timespec timeout = {5, 0}; // 5 seconds timeout

        n = epoll_pwait2(epoll_fd, events, MAX_EVENTS, &timeout, NULL, MIN_EVENTS);
        if (n == -1) {
            perror("epoll_pwait2");
            break;
        }

        for (i = 0; i < n; i++) {
            if (events[i].data.fd == listen_fd) {
                // Accept new connections
                while (1) {
                    int conn_fd = accept(listen_fd, NULL, NULL);
