Certainly! Below is a concise C example demonstrating how to use `sendfile()` with a `chunk_size` of 1MB to transfer a large file over a TCP socket. The example includes basic error handling for partial sends.

```c
#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/sendfile.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <errno.h>

#define CHUNK_SIZE (1024 * 1024) // 1MB

int main(int argc, char *argv[]) {
    if (argc != 4) {
        fprintf(stderr, "Usage: %s <file> <ip> <port>\n", argv[0]);
        return EXIT_FAILURE;
    }

    const char *filename = argv[1];
    const char *ip = argv[2];
    int port = atoi(argv[3]);

    int file_fd = open(filename, O_RDONLY);
    if (file_fd < 0) {
        perror("open");
        return EXIT_FAILURE;
    }

    int sock_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (sock_fd < 0) {
        perror("socket");
        close(file_fd);
        return EXIT_FAILURE;
    }

    struct sockaddr_in server_addr = {
        .sin_family = AF_INET,
        .sin_port = htons(port),
    };
    if (inet_pton(AF_INET, ip, &server_addr.sin_addr) <= 0) {
        perror("inet_pton");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    if (connect(sock_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("connect");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    off_t offset = 0;
    ssize_t bytes_sent;
    struct stat file_stat;
    if (fstat(file_fd, &file_stat) < 0) {
        perror("fstat");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    while (offset < file_stat.st_size) {
        size_t bytes_to_send = CHUNK_SIZE;
        if (offset + bytes_to_send > file_stat.st_size) {
            bytes_to_send = file_stat.st_size - offset;
        }

        bytes_sent = sendfile(sock_fd, file_fd, &offset, bytes_to_send);
        if (bytes_sent <= 0) {
            if (errno == EINTR || errno == EAGAIN) {
                continue; // Retry on interrupt or temporary unavailability
            }
            perror("sendfile");
            close(file_fd);
            close(sock_fd);
            return EXIT_FAILURE;
        }
    }

    printf("File transfer completed successfully.\n");

    close(file_fd);
    close(sock_fd);
    return EXIT_SUCCESS;
}
```

### Key Points:
- **Error Handling**: The code checks for errors at each step, including opening the file, creating the socket, connecting, and during the `sendfile()` call.
- **Partial Sends**: The loop continues until the entire file is sent, handling partial sends by adjusting the `offset` and `bytes_to_send`.
- **Chunk Size**: The `CHUNK_SIZE` is set to 1MB, and the code ensures that the last chunk does not exceed the file size.
- **Socket Connection**: The example assumes a TCP connection to a server specified by IP and port. Adjust the server-side to accept this connection for a complete test.

대용량 파일을 TCP 소켓으로 전송할 때 `sendfile()`을 사용하여 `chunk_size`를 1MB로 설정하고, 부분 전송에 대한 오류 처리를 포함한 간단한 C 예시 코드를 작성해 보겠습니다.

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/sendfile.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <string.h>
#include <errno.h>

#define CHUNK_SIZE (1024 * 1024) // 1MB

int main(int argc, char *argv[]) {
    if (argc != 4) {
        fprintf(stderr, "Usage: %s <file> <ip> <port>\n", argv[0]);
        return EXIT_FAILURE;
    }

    const char *filename = argv[1];
    const char *ip = argv[2];
    int port = atoi(argv[3]);

    int file_fd = open(filename, O_RDONLY);
    if (file_fd < 0) {
        perror("open");
        return EXIT_FAILURE;
    }

    int sock_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (sock_fd < 0) {
        perror("socket");
        close(file_fd);
        return EXIT_FAILURE;
    }

    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(port);
    if (inet_pton(AF_INET, ip, &server_addr.sin_addr) <= 0) {
        perror("inet_pton");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    if (connect(sock_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("connect");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    off_t offset = 0;
    ssize_t bytes_sent;
    struct stat file_stat;
    if (fstat(file_fd, &file_stat) < 0) {
        perror("fstat");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    while (offset < file_stat.st_size) {
        size_t bytes_to_send = CHUNK_SIZE;
        if (offset + bytes_to_send > file_stat.st_size) {
            bytes_to_send = file_stat.st_size - offset;
        }

        bytes_sent = sendfile(sock_fd, file_fd, &offset, bytes_to_send);
        if (bytes_sent <= 0) {
            if (errno == EINTR || errno == EAGAIN) {
                continue; // Retry on interrupt or temporary unavailability
            }
            perror("sendfile");
            break;
        }
    }

    close(file_fd);
    close(sock_fd);

    return EXIT_SUCCESS;
}
```

